import React, { useEffect, useState } from "react";
import "./App.css";
import AddAssignment from "./components/AddAssignment";
import AssignmentList from "./components/AssignmentList";
import Stats from "./components/Stats";
import Login from "./Login";

function App() {
  const [assignments, setAssignments] = useState([]);
  const [stats, setStats] = useState({});
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const userId = localStorage.getItem("userId");

  useEffect(() => {
    if (userId) {
      setIsLoggedIn(true);
      fetchData();
    }
  }, []);

  const fetchData = async () => {
    if (!userId) return;

    const a = await fetch(
      `http://localhost:8080/assignments/user/${userId}`
    );
    const s = await fetch(
      `http://localhost:8080/assignments/stats/${userId}`
    );

    setAssignments(await a.json());
    setStats(await s.json());
  };

  const submit = async (id) => {
    await fetch(`http://localhost:8080/assignments/submit/${id}`, {
      method: "PUT",
    });
    fetchData();
  };

  const logout = () => {
    localStorage.removeItem("userId");
    setIsLoggedIn(false);
  };

  // 🔐 If not logged in → show Login page
  if (!isLoggedIn) {
    return <Login setIsLoggedIn={setIsLoggedIn} />;
  }

  return (
    <div className="app-container">
      <h1>AssignTrack - Assignment Submission Tracker</h1>

      <button
        onClick={logout}
        style={{
          marginBottom: "20px",
          padding: "8px 15px",
          background: "#ef4444",
          color: "white",
          border: "none",
          borderRadius: "8px",
          cursor: "pointer",
        }}
      >
        Logout
      </button>

      <AddAssignment refresh={fetchData} userId={userId} />

      <AssignmentList
        assignments={assignments}
        submit={submit}
      />

      <Stats stats={stats} />
    </div>
  );
}

export default App;
